  1	import * as React from "react";
  2	import { useField } from "formik";
  3	import {
  4	  FormGroup,
  5	  FormHelperText,
  6	  HelperText,
  7	  HelperTextItem,
  8	  MenuToggle,
  9	  MenuToggleElement,
 10	  Select,
 11	  SelectProps,
 12	  Spinner,
 13	  TextInputGroup,
 14	  TextInputGroupMain,
 15	} from "@patternfly/react-core";
 16	
 17	import { getFieldId } from "../../copiedFromConsole/formik-fields/field-utils";
 18	import { FieldProps } from "../../copiedFromConsole/formik-fields/field-types";
 19	import { useFormikValidationFix } from "../../copiedFromConsole/hooks/formik-validation-fix";
 20	import { ExclamationCircleIcon } from "@patternfly/react-icons";
 21	import { useNodeHealthCheckTranslation } from "../../localization/useNodeHealthCheckTranslation";
 22	
 23	export interface MultiSelectFieldProps extends FieldProps {
 24	  placeholderText?: string;
 25	  isLoading: boolean;
 26	  isRequired: boolean;
 27	  label: string;
 28	  filterValue: string;
 29	  setFilterValue: (filterValue: string) => void;
 30	  children: SelectProps["children"];
 31	}
 32	
 33	const MultiSelectField: React.FC<MultiSelectFieldProps> = ({
 34	  label,
 35	  helpText,
 36	  labelIcon,
 37	  isRequired,
 38	  filterValue,
 39	  setFilterValue,
 40	  isLoading,
 41	  children,
 42	  ...props
 43	}) => {
 44	  const { t } = useNodeHealthCheckTranslation();
 45	  const [isOpen, setOpen] = React.useState(false);
 46	  const [field, { touched, error }, { setValue }] = useField<string[]>(
 47	    props.name
 48	  );
 49	  const textInputRef = React.useRef<HTMLInputElement>();
 50	  const fieldId = getFieldId(props.name, "multiinput");
 51	  const isValid = !(touched && error);
 52	  const errorMessage = !isValid ? error : "";
 53	  useFormikValidationFix(field.value);
 54	
 55	  const containerRef = React.useRef<HTMLDivElement>(null);
 56	
 57	  const onToggle = (isOpen: boolean) => setOpen(isOpen);
 58	  const onClearSelection = () => {
 59	    setValue([]);
 60	    setOpen(false);
 61	  };
 62	
 63	  const onSelect: SelectProps["onSelect"] = (event, selection) => {
 64	    let newValue: string[];
 65	    if (field.value.includes(selection as string)) {
 66	      newValue = field.value.filter((sel: string) => sel !== selection);
 67	    } else {
 68	      newValue = [...field.value, selection as string];
 69	    }
 70	    setValue(newValue);
 71	  };
 72	
 73	  const validated = isValid ? "default" : "error";
 74	
 75	  const formContent = isLoading ? (
 76	    <Spinner size="md" />
 77	  ) : (
 78	    <div
 79	      ref={containerRef}
 80	      onBlur={(e) => {
 81	        const next = (e.relatedTarget as Node) || null;
 82	        if (
 83	          next &&
 84	          containerRef.current &&
 85	          containerRef.current.contains(next)
 86	        ) {
 87	          return;
 88	        }
 89	        setOpen(false);
 90	      }}
 91	    >
 92	      <Select
 93	        {...field}
 94	        {...props}
 95	        id={fieldId}
 96	        validated={isValid ? "default" : "error"}
 97	        aria-describedby={`${fieldId}-helper`}
 98	        placeholderText={t("Filter by label")}
 99	        isOpen={isOpen}
100	        onToggle={onToggle}
101	        onSelect={onSelect}
102	        selections={field.value}
103	        onClear={onClearSelection}
104	        maxHeight={400}
105	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
106	          <MenuToggle
107	            variant="typeahead"
108	            ref={toggleRef}
109	            onClick={() => setOpen(!isOpen)}
110	            isExpanded={isOpen}
111	            isFullWidth
112	          >
113	            <TextInputGroup isPlain>
114	              <TextInputGroupMain
115	                value={filterValue}
116	                onClick={() => onToggle(!isOpen)}
117	                onChange={(_, val) => setFilterValue(val)}
118	                onKeyDown={() => onToggle(true)}
119	                id="multi-typeahead-select-checkbox-input"
120	                autoComplete="off"
121	                innerRef={textInputRef}
122	                placeholder={t("Filter by label")}
123	                role="combobox"
124	                isExpanded={isOpen}
125	                aria-controls="select-multi-typeahead-checkbox-listbox"
126	              />
127	            </TextInputGroup>
128	          </MenuToggle>
129	        )}
130	        maxMenuHeight="25rem"
131	        isScrollable
132	        appendTo={() => containerRef.current || document.body}
133	      >
134	        {children}
135	      </Select>
136	      <FormHelperText>
137	        <HelperText>
138	          <HelperTextItem
139	            variant={validated}
140	            {...(validated === "error" && { icon: <ExclamationCircleIcon /> })}
141	          >
142	            {errorMessage || helpText}
143	          </HelperTextItem>
144	        </HelperText>
145	      </FormHelperText>
146	    </div>
147	  );
148	
149	  return (
150	    <FormGroup
151	      fieldId={fieldId}
152	      label={label}
153	      isRequired={isRequired}
154	      labelHelp={labelHelp}
155	      data-test={`multi-select-${label}`}
156	    >
157	      {formContent}
158	    </FormGroup>
159	  );
160	};
161	
162	export default MultiSelectField;

